items.snippet:
gsap.registerPlugin(Physics2DPlugin);
particles.forEach((p) =>
  gsap.to(p, {
    physics2D: {
      velocity: gsap.utils.random(150, 400),
      angle: gsap.utils.random(200, 340),
      gravity: 600,
    },
    autoAlpha: 0,
    duration: gsap.utils.random(1.5, 2.5),
    onComplete: () => p.remove(),
  }),
);

gsap.to(el, {
  autoAlpha: 1,
  duration: gsap.utils.random(0.8, 1.4),
  delay: i * 0.1,
  physics2D: {
    velocity: gsap.utils.random(100, 200),
    angle: 90,
    gravity: 800,
    friction: 0.1,
  },
}); // on active

el.addEventListener('mouseenter', () =>
  gsap.to(card, { y: -8, scale: 1.02, boxShadow: '0 12px 24px rgba(0,0,0,0.25)', duration: 0.3 }),
);
el.addEventListener('mouseleave', () => gsap.to(card, { y: 0, scale: 1, clearProps: 'boxShadow', duration: 0.3 }));

const rxTo = gsap.quickTo(card, 'rotationX', { duration: 0.4, ease: 'power2.out' });
const ryTo = gsap.quickTo(card, 'rotationY', { duration: 0.4, ease: 'power2.out' });
el.addEventListener('mousemove', (e) => {
  const r = card.getBoundingClientRect();
  ryTo(gsap.utils.mapRange(0, r.width, -10, 10)(e.clientX - r.left));
  rxTo(gsap.utils.mapRange(0, r.height, 10, -10)(e.clientY - r.top));
});

cards.forEach((c, i) =>
  gsap.to(c, {
    rotation: (i - (cards.length - 1) / 2) * 8,
    x: (i - (cards.length - 1) / 2) * 40,
    y: -Math.abs(i - (cards.length - 1) / 2) * 6,
    duration: 0.5,
    ease: 'back.out(1.4)',
  }),
);

const xTo = gsap.quickTo(el, 'x', { duration: 0.4, ease: 'power2.out' });
const yTo = gsap.quickTo(el, 'y', { duration: 0.4, ease: 'power2.out' });
// mousemove: xTo((e.clientX - cx) * 0.3); yTo((e.clientY - cy) * 0.3);
// mouseleave: xTo(0); yTo(0);

gsap.set('.shine', { xPercent: -120, skewX: -20 });
const tl = gsap
  .timeline({ paused: true })
  .to('.shine', { xPercent: 220, duration: 0.7, ease: 'power2.inOut' });
// on step / hover: tl.restart();

const tl = gsap
  .timeline({ paused: true })
  .to(btn, { width: 56, borderRadius: 28, duration: 0.35, ease: 'power2.inOut' })
  .to('.label', { autoAlpha: 0, duration: 0.2 }, '<')
  .to('.icon', { autoAlpha: 1, duration: 0.2 }, '<0.15');
// state change: on ? tl.play() : tl.reverse();

const open = () => {
  gsap.set(panel, { height: 'auto' });
  gsap.from(panel, { height: 0, autoAlpha: 0, duration: 0.4, ease: 'power2.inOut' });
};
const close = () => gsap.to(panel, { height: 0, autoAlpha: 0, duration: 0.35, ease: 'power2.inOut' });

const obj = { value: 0 };
gsap.to(obj, {
  value: target,
  duration: 2,
  ease: 'power2.out',
  onUpdate: () => {
    el.textContent = Math.round(obj.value).toLocaleString() + suffix;
  },
}); // on active

gsap.set(els, {
  x: () => gsap.utils.random(-40, 40),
  y: () => gsap.utils.random(20, 60),
  rotation: () => gsap.utils.random(-12, 12),
  autoAlpha: 0,
});
gsap.to(els, {
  x: 0,
  y: 0,
  rotation: 0,
  autoAlpha: 1,
  ease: 'power3.out',
  duration: () => gsap.utils.random(0.6, 1.0),
  stagger: { each: 0.08, from: 'random' },
}); // on active

const wrapX = gsap.utils.wrap(-100, 100);
gsap.to(els, {
  x: '+=200',
  duration: 10,
  ease: 'none',
  repeat: -1,
  modifiers: { x: gsap.utils.unitize(wrapX) },
});

function float(el) {
  gsap.to(el, {
    x: gsap.utils.random(-30, 30),
    y: gsap.utils.random(-20, 20),
    rotation: gsap.utils.random(-8, 8),
    duration: gsap.utils.random(3, 6),
    ease: 'sine.inOut',
    onComplete: () => float(el),
  });
}

gsap.to('[track]', {
  x: -(track.scrollWidth / 2),
  duration: 20,
  ease: 'none',
  repeat: -1,
  modifiers: {
    x: gsap.utils.unitize((x) => parseFloat(x) % (track.scrollWidth / 2)),
  },
});

const tl = gsap.timeline({ repeat: -1 });
shapes.forEach((s) =>
  tl.to('#blob', { morphSVG: { shape: s, type: 'rotational' }, duration: 4, ease: 'power1.inOut' }),
);

gsap.registerPlugin(DrawSVGPlugin);
gsap.set('[sel]', { drawSVG: '0% 0%' });
gsap.to('[sel]', { drawSVG: '0% 100%', duration: 1.5, ease: 'power2.inOut' });

gsap.set('[sel]', { drawSVG: '0% 100%' }); // fully visible
gsap.to('[sel]', { drawSVG: '100% 100%', duration: 1.2, ease: 'power2.in' }); // erase L to R
// moving window: fromTo { drawSVG: '0% 10%' } -> { drawSVG: '90% 100%', repeat: -1, ease: 'none' }

gsap.set('[sel] path', { drawSVG: '0% 0%', autoAlpha: 1 });
const tl = gsap.timeline();
paths.forEach((p, i) =>
  tl.to(p, { drawSVG: '0% 100%', duration: 0.6, ease: 'power1.inOut' }, i ? '-=0.1' : 0),
);

const tl = gsap
  .timeline({ paused: true })
  .fromTo('[sel]', { drawSVG: '0% 0%' }, { drawSVG: '0% 100%', ease: 'none' });
// on step change: tl.tweenTo(step / totalSteps);

gsap.registerPlugin(MorphSVGPlugin);
MorphSVGPlugin.convertToPath('[start], [end]');
gsap.to('[start]', {
  morphSVG: { shape: '[end]', type: 'rotational', shapeIndex: 'auto' },
  duration: 1.2,
  ease: 'power2.inOut',
});

let on = false;
el.addEventListener('click', () => {
  on = !on;
  gsap.to('#icon-a', { morphSVG: on ? dataB : dataA, duration: 0.4, ease: 'power2.inOut' });
});

const tl = gsap.timeline({ paused: true });
shapes.forEach((s) =>
  tl.to('#morph', { morphSVG: { shape: s, type: 'rotational' }, duration: 1 }),
);
// step change -> tl.tweenTo(step / shapes.length);

gsap.registerPlugin(MotionPathPlugin);
gsap.to('[el]', {
  motionPath: { path: '[path]', align: '[path]', alignOrigin: [0.5, 0.5], autoRotate: false },
  duration: 2,
  ease: 'power1.inOut',
}); // on active

gsap.to('[el]', {
  motionPath: { path: '[path]', align: '[path]', alignOrigin: [0.5, 0.5], autoRotate: true },
  duration: 2,
  ease: 'power1.inOut',
});
// orbit loop: drop the trigger, add repeat: -1, ease: 'none'

const tl = gsap.timeline({ paused: true }).to('[el]', {
  motionPath: {
    path: '[path]', align: '[path]', alignOrigin: [0.5, 0.5],
    autoRotate: true, start: 0, end: 1,
  },
  ease: 'none',
});
// step change -> tl.progress(step / total);

// inject filter: feTurbulence#liquid-turbulence + feDisplacementMap#liquid-displacement (scale 0)
gsap.to('#liquid-turbulence', { attr: { baseFrequency: '0.65 0.75' }, duration: 0.4 });
gsap.to('#liquid-displacement', { attr: { scale: 30 }, duration: 0.4 });

SplitText.create('[sel]', {
  type: 'lines',
  mask: 'lines',
  autoSplit: true,
  onSplit: (self) =>
    gsap.from(self.lines, { yPercent: 110, duration: 0.9, stagger: 0.1, ease: 'power4.out' }),
});

// parent: perspective: 400px
gsap.from(split.chars, {
  rotationX: 90,
  transformOrigin: '0% 50% -50',
  autoAlpha: 0,
  duration: 0.7,
  stagger: 0.04,
  ease: 'back.out(2)',
});

gsap.registerPlugin(ScrambleTextPlugin);
gsap.to('[sel]', {
  duration: 2,
  ease: 'none',
  scrambleText: { text: '[final]', chars: 'upperAndLowerCase', revealDelay: 0.3, speed: 0.4 },
}); // on active

gsap.to('[sel]', {
  duration: 2,
  ease: 'none',
  scrambleText: { text: '[final]', chars: '01', revealDelay: 0.3, speed: 0.4 },
});

gsap.registerPlugin(TextPlugin);
gsap.set('[sel]', { text: '' });
gsap.to('[sel]', { duration: 2, ease: 'none', text: '[your text]', delay: 0.5 }); // on active

const tl = gsap.timeline({ repeat: -1, defaults: { ease: 'power2.out' } });
words.forEach((w) =>
  tl
    .to('.rotating-word', { autoAlpha: 0, duration: 0.3 })
    .set('.rotating-word', { text: w })
    .to('.rotating-word', { autoAlpha: 1, duration: 0.4 })
    .to({}, { duration: 2 }),
);

const tl = gsap.timeline();
tl.to('.red', { x: gsap.utils.random(-4, 4), skewX: gsap.utils.random(-2, 2), duration: 0.08 })
  .to('.cyan', { x: gsap.utils.random(-4, 4), skewX: gsap.utils.random(-2, 2), duration: 0.08 }, '<')
  .to(['.red', '.cyan'], { x: 0, skewX: 0, duration: 0.06 });
gsap.delayedCall(gsap.utils.random(2, 6), glitchBurst);

gsap
  .timeline()
  .to('[sel]', { skewX: gsap.utils.random(-4, 4), duration: 0.06 })
  .to('[sel]', { skewX: 0, duration: 0.08 });
gsap.delayedCall(gsap.utils.random(3, 8), glitchBurst);

gsap.to(card, {
  rotationY: flipped ? 0 : 180,
  duration: 0.6,
  ease: 'power2.inOut',
  transformPerspective: 1000,
});

gsap.registerPlugin(Flip);
const state = Flip.getState(card);
card.classList.add('expanded'); // or move into a bigger container
Flip.from(state, { duration: 0.5, ease: 'power2.inOut', absolute: true });

const state = Flip.getState('.card');
// toggle display: none on non-matching cards
Flip.from(state, {
  duration: 0.5,
  ease: 'power2.inOut',
  absolute: true,
  onEnter: (els) => gsap.from(els, { autoAlpha: 0, duration: 0.3 }),
  onLeave: (els) => gsap.to(els, { autoAlpha: 0, duration: 0.2 }),
});

gsap.set('#overlay', { scaleX: 0, transformOrigin: 'left center' });
// enter: from scaleX: 1 (origin right) -> scaleX: 0, duration: 0.6, ease: 'power3.inOut'
// exit:  to scaleX: 1 (origin left), then advance in onComplete

const toAngle = gsap.utils.mapRange(0, 1, -90, 90);
const clamp01 = gsap.utils.clamp(0, 1);
// on step change:
gsap.set('[dial]', { rotation: toAngle(clamp01(step / totalSteps)) });

const toX = gsap.utils.mapRange(0, window.innerWidth, -30, 30);
const xTo = gsap.quickTo('[sel]', 'x', { duration: 0.4, ease: 'power2.out' });
window.addEventListener('pointermove', (e) => xTo(toX(e.clientX)));

const mix = gsap.utils.interpolate('#0EA5E9', '#F59E0B');
// on step change:
gsap.set('[sel]', { color: mix(step / totalSteps) });

gsap.from('[sel] .cell', {
  scale: 0,
  autoAlpha: 0,
  duration: 0.5,
  ease: 'power2.out',
  stagger: gsap.utils.distribute({ amount: 0.8, from: 'center', grid: 'auto' }),
});

const transform = gsap.utils.pipe(
  gsap.utils.normalize(0, totalSteps),
  gsap.utils.mapRange(0, 1, 0, 100),
  gsap.utils.snap(5),
);
// transform(step) -> 0..100 snapped to 5s

gsap.registerPlugin(Draggable, InertiaPlugin);
Draggable.create('[sel]', {
  type: 'x,y',
  inertia: true,
  snap: { x: gsap.utils.snap(80), y: gsap.utils.snap(80) },
});

gsap.registerPlugin(CustomEase);
CustomEase.create('brandEase', '.17,.67,.35,1.2');
gsap.to('[sel]', { y: 0, duration: 0.8, ease: 'brandEase' });

Draggable.create('[track]', {
  type: 'x',
  inertia: true,
  bounds: { minX: -(panels - 1) * panelW, maxX: 0 },
  snap: { x: gsap.utils.snap(panelW) },
});

gsap.registerPlugin(Observer);
let isAnimating = false;
Observer.create({
  type: 'touch,pointer,wheel',
  onUp: () => !isAnimating && next(),
  onDown: () => !isAnimating && prev(),
});
